#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long L, K; scanf("%lld %lld", &L, &K);
        long long ans = (L % K == 0) ? 0 : 1;
        printf("%lld\n", ans);
    }
    return 0;
}

